  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n  output   = \"../src/generated/client\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// Enum untuk melacak status permintaan\nenum RequestStatus {\n  OPEN // Permintaan masih dibuka\n  FULFILLED // Permintaan sudah terpenuhi\n  CANCELLED\n  REQUESTED\n  FULFILLING\n  CONFIRMED // Permintaan dibatalkan\n}\n\nmodel termsCondition {\n  id        String   @id @default(cuid())\n  userid    String\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Notification {\n  id           String   @id @default(cuid())\n  notification String\n  userid       String\n  notifType    String\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  // Relasi ke Donation yang lama bisa dihapus jika tidak dipakai lagi\n  // donations         Donation[]\n}\n\n// Model untuk Campaign (TIDAK BERUBAH)\nmodel Campaign {\n  id                String   @id @default(cuid())\n  title             String\n  description       String\n  targetAmount      Float\n  currentAmount     Float    @default(0)\n  createdAt         DateTime @default(now())\n  updatedAt         DateTime @updatedAt\n  creatorFirebaseId String\n\n  // Relasi ke Donation yang lama bisa dihapus jika tidak dipakai lagi\n  // donations         Donation[]\n}\n\n// --- MODEL BARU UNTUK PERMINTAAN DONASI BARANG ---\nmodel DonationRequest {\n  id String @id @default(cuid())\n\n  // Info Requestor\n  requestorFirebaseId String // ID dari Firebase Auth\n  requestorName       String // Nama pemohon\n  donationType        String?\n  detailBarang        String?\n  alasanDonasi        String?\n  // Info Lokasi\n  locationDescription String // Alamat atau deskripsi lokasi\n  latitude            Float? // Opsional\n  longitude           Float? // Opsional\n  city                String? // Kota (opsional)\n  // Info Donasi\n  description         String // Penjelasan kenapa butuh donasi\n  itemType            String // Jenis barang yang dibutuhkan (mis: \"Pakaian\", \"Beras\")\n  itemWeight          Float? // Perkiraan berat barang (opsional)\n  weightUnit          String? // Satuan berat (mis: \"kg\", \"liter\") (opsional)\n\n  // Status & Timestamps\n  status    RequestStatus @default(OPEN) // Status default adalah OPEN\n  createdAt DateTime      @default(now())\n  updatedAt DateTime      @updatedAt\n  expiredAt DateTime?\n\n  photoDonations PhotoDonation[]\n\n  // Relasi ke fulfillment\n  fulfillments         DonationFulfillment[]\n  chatRooms            ChatRoom[]\n  donationRequestments DonationRequestment[]\n}\n\nmodel PhotoDonation {\n  id                String          @id @default(cuid())\n  imageFile         String\n  createdAt         DateTime        @default(now())\n  updatedAt         DateTime        @updatedAt\n  donationRequestId String\n  donationRequest   DonationRequest @relation(fields: [donationRequestId], references: [id])\n}\n\n// --- MODEL BARU UNTUK MENCATAT PEMENUHAN DONASI (DARI DONATUR) ---\nmodel DonationFulfillment {\n  id        String   @id @default(cuid())\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Info Donatur\n  donorFirebaseId        String // ID Firebase dari donatur\n  donorRequestFirebaseId String?\n  donorName              String // Nama donatur\n  donorNotes             String // Catatan dari donatur (opsional)\n  latitude               Float? // Lokasi donatur (opsional)\n  longitude              Float? // Lokasi donatur (opsional)\n  address                String? // Alamat donatur (opsional)\n  city                   String?\n  status                 RequestStatus   @default(FULFILLING) // Status default adalah OPEN\n  // Kota donatur (opsional)\n  // Relasi ke Permintaan Donasi yang dipenuhi\n  // Ini akan menghubungkan donasi ini ke permintaan spesifik\n  donationRequestId      String\n  donationRequest        DonationRequest @relation(fields: [donationRequestId], references: [id])\n  chatRoom               ChatRoom?\n}\n\nmodel DonationRequestment {\n  id                String          @id @default(cuid())\n  createdAt         DateTime        @default(now())\n  updatedAt         DateTime        @updatedAt\n  requestorId       String // ID Firebase dari donatur\n  donorFirebaseId   String?\n  status            RequestStatus   @default(REQUESTED) // Status default adalah OPEN\n  donorName         String // Nama donatur\n  reason            String // Catatan dari donatur (opsional)\n  latitude          Float? // Lokasi donatur (opsional)\n  longitude         Float? // Lokasi donatur (opsional)\n  address           String? // Alamat donatur (opsional)\n  city              String? // Kota donatur (opsional)\n  donationRequestId String\n  donationRequest   DonationRequest @relation(fields: [donationRequestId], references: [id])\n  chatRoom          ChatRoom?\n}\n\nmodel Token {\n  id        String   @id @default(uuid())\n  email     String\n  token     String   @unique\n  expiresAt DateTime\n  createdAt DateTime @default(now())\n}\n\nmodel User {\n  id        String  @id @default(uuid())\n  name      String?\n  email     String? @unique\n  role      String?\n  password  String?\n  isActive  Boolean @default(false)\n  isDonate  Boolean @default(false)\n  isPhotoId Boolean @default(false)\n\n  identificationNumber String?\n  photoKtp             String?\n  // Nama relasi di sini harus sama dengan yang ada di model Chat\n  sentMessages         Chat[]  @relation(\"UserSentChats\")\n  readMessages         Chat[]  @relation(\"UserReadBy\")\n\n  rooms     ChatRoomMember[]\n  createdAt DateTime         @default(now())\n  updatedAt DateTime         @default(now())\n}\n\nmodel ChatRoom {\n  id     String @id @default(uuid())\n  roomId String @unique\n\n  // Relasi ke DonationRequest\n  donationRequestId String\n  donation          DonationRequest @relation(fields: [donationRequestId], references: [id], onDelete: Cascade)\n\n  // Relasi balik ke Fulfillment\n  fulfillmentId String?              @unique\n  fulfillment   DonationFulfillment? @relation(fields: [fulfillmentId], references: [id])\n\n  // Relasi balik ke Requestment\n  requestmentId String?              @unique\n  requestment   DonationRequestment? @relation(fields: [requestmentId], references: [id])\n\n  isActive    Boolean  @default(true)\n  lastMessage String   @default(\"\")\n  lastSeen    DateTime @default(now())\n  unreadCount Int      @default(0)\n\n  members ChatRoomMember[]\n  chats   Chat[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Hapus @@unique([donationRequestId]) jika ingin banyak chat per donasi\n}\n\nmodel ChatRoomMember {\n  userId String\n  roomId String\n\n  user User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  room ChatRoom @relation(fields: [roomId], references: [id], onDelete: Cascade)\n\n  joinedAt DateTime @default(now())\n\n  @@id([userId, roomId])\n  @@index([roomId])\n}\n\nmodel Chat {\n  id String @id @default(uuid())\n\n  roomId String\n  room   ChatRoom @relation(fields: [roomId], references: [id], onDelete: Cascade)\n\n  // Pengirim: Menggunakan nama relasi \"UserSentChats\" agar cocok dengan User\n  senderId String\n  sender   User   @relation(\"UserSentChats\", fields: [senderId], references: [id], onDelete: Cascade)\n\n  message String\n\n  // Pembaca: Menggunakan nama relasi \"UserReadBy\" agar cocok dengan User\n  readBy User[] @relation(\"UserReadBy\")\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@index([roomId])\n}\n\n// --- MODEL BARU UNTUK SEJARAH DONASI UANG ---\nmodel FundDonationHistory {\n  id String @id @default(cuid())\n\n  // Info Requestor\n  requestorFirebaseId String // ID dari Firebase Auth\n  donatorName         String // Nama donor\n  donatorDateTime     DateTime @default(now()) // Tanggal dan jam donor berdonasi\n\n  // Info Donasi\n  amount         Decimal // Jumlah donasi\n  paymentProcess String // Jenis pembayaran untuk donasi uang\n}\n",
